class NoConsecutiveBlankLinesRuleClassWithoutBodyAtEofTest {
    private val noConsecutiveBlankLinesRuleAssertThat = assertThatRule { NoConsecutiveBlankLinesRule() }

    @Test
    fun `Given class without body followed by consecutive blank lines at end of file then do return a lint error`() {
        val code =
            """
            sealed class Hello



            """.trimIndent()
        val formattedCode =
            """
            sealed class Hello

            """.trimIndent()

        noConsecutiveBlankLinesRuleAssertThat(code)
            .hasLintViolation(3, 1, "Needless blank line(s)")
            .isFormattedAs(formattedCode)
    }
}
"}

